import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  featureOptions: string[]; // Available feature options for the checkbox step
  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all collected answers as a structured object */
type ActionSubmitPayload = { name: string; email: string; satisfaction: number; features: string[]; comments: string };





// Place helper components here if needed

const StepIndicator = ({ current, total }: { current: number; total: number }) => (
  <Box paddingBottom={6}>
    <Heading level={4}>Step {current} of {total}</Heading>
    <Progress value={current} max={total} size="sm" />
  </Box>
);

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const submitAction = useAction<ActionSubmitPayload>('submit'); // Called with all collected answers as a structured object

  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    satisfaction: 3,
    features: [] as string[],
    comments: '',
  });
  const [errors, setErrors] = useState({ name: false, email: false });

  const totalSteps = 4;

  const validateEmail = (email: string) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);

  const canGoNext = useMemo(() => {
    if (step === 1) return formData.name.trim() !== '' && validateEmail(formData.email);
    return true;
  }, [step, formData]);

  const handleNext = () => {
    if (step === 1) {
      const nameError = formData.name.trim() === '';
      const emailError = !validateEmail(formData.email);
      setErrors({ name: nameError, email: emailError });
      if (nameError || emailError) return;
    }
    setStep((s) => Math.min(s + 1, totalSteps));
  };

  const handleBack = () => setStep((s) => Math.max(s - 1, 1));

  const toggleFeature = (feature: string) => {
    setFormData((prev) => ({
      ...prev,
      features: prev.features.includes(feature)
        ? prev.features.filter((f) => f !== feature)
        : [...prev.features, feature],
    }));
  };

  const handleSubmit = () => {
    submitAction({
      name: formData.name,
      email: formData.email,
      satisfaction: formData.satisfaction,
      features: formData.features,
      comments: formData.comments,
    });
  };

  return (
    <Container maxWidth="md" padding={6}>
      <Card padding={6} shadow="lg" radius="lg">
        {step < totalSteps && <StepIndicator current={step} total={totalSteps - 1} />}

        {step === 1 && (
          <Stack gap={4}>
            <Heading level={2}>Step 1: Your Information</Heading>
            <Input label="Name" value={formData.name} onChange={(v) => setFormData({...formData, name: v})} error={errors.name ? 'Name is required' : ''} />
            <Input label="Email" value={formData.email} onChange={(v) => setFormData({...formData, email: v})} error={errors.email ? 'Valid email required' : ''} />
          </Stack>
        )}

        {step === 2 && (
          <Stack gap={4}>
            <Heading level={2}>Step 2: Satisfaction</Heading>
            <RadioGroup
              label="How satisfied are you?"
              value={formData.satisfaction.toString()}
              onChange={(v) => setFormData({...formData, satisfaction: parseInt(v)})}
              options={props.satisfactionLabels.map((l, i) => ({ value: (i + 1).toString(), label: l }))}
            />
          </Stack>
        )}

        {step === 3 && (
          <Stack gap={4}>
            <Heading level={2}>Step 3: Interests</Heading>
            <Text>Which features are you interested in?</Text>
            {props.featureOptions.map((f) => (
              <Checkbox key={f} label={f} checked={formData.features.includes(f)} onChange={() => toggleFeature(f)} />
            ))}
          </Stack>
        )}

        {step === 4 && (
          <Stack gap={4}>
            <Heading level={2}>Step 4: Comments and Review</Heading>
            <TextArea label="Comments" value={formData.comments} onChange={(v) => setFormData({...formData, comments: v})} maxLength={500} />
            <Text>{formData.comments.length} / 500 characters</Text>
            <Box background="var(--ggui-color-surfaceVariant)" padding={4} borderRadius="var(--ggui-shape-radius-md)">
              <Text><strong>Name:</strong> {formData.name}</Text>
              <Text><strong>Email:</strong> {formData.email}</Text>
              <Text><strong>Satisfaction:</strong> {props.satisfactionLabels[formData.satisfaction - 1]}</Text>
              <Text><strong>Features:</strong> {formData.features.join(', ') || 'None'}</Text>
              <Text><strong>Comments:</strong> {formData.comments || 'No comments'}</Text>
            </Box>
          </Stack>
        )}

        <Spacer size={6} />

        <Row gap={4} justify="between">
          {step > 1 && <Button variant="secondary" onClick={handleBack}>Back</Button>}
          {step < totalSteps && <Button onClick={handleNext} disabled={!canGoNext}>Next</Button>}
          {step === totalSteps && <Button variant="primary" onClick={handleSubmit}>Submit</Button>}
        </Row>
      </Card>
    </Container>
  );
}

