                  <RatingStars rating={(review as any)?.rating || 0} />
                </Row>
                <Text variant="bodySmall">{(review as any)?.text || ''}</Text>
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">{(review as any)?.date || ''}</Text>
              </Stack>
            </Card>
          ))}

        </Stack>
      ),
    },
  ], [props.product.description, props.product.specifications, props.product.reviews]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-8)">
        <Row gap="var(--ggui-spacing-8)" align="start">
          <Box background="var(--ggui-color-surfaceVariant)" padding="var(--ggui-spacing-12)" borderRadius="var(--ggui-shape-radius-lg)" style={{ flex: '1' }}>
            <Text variant="label" align="center">{props.product.name}</Text>
          </Box>
          <Stack gap="var(--ggui-spacing-4)" style={{ flex: '1' }}>
            <Heading level={1}>{props.product.name}</Heading>
            <Text variant="bodyLarge" weight="bold">{props.product.currency}{props.product.price?.toFixed(2)}</Text>
            <RatingStars rating={props.product.rating || 0} />
            <Badge variant={maxStock > 5 ? 'success' : 'warning'}>
              {isOutOfStock ? 'Out of Stock' : maxStock <= 5 ? `Low Stock (${maxStock})` : 'In Stock'}
            </Badge>
          </Stack>
        </Row>

        <Tabs items={tabs} variant="line" />

        <Card padding="var(--ggui-spacing-6)">
          <Row gap="var(--ggui-spacing-4)" align="center">
            <Row align="center" gap="var(--ggui-spacing-2)">
              <Button as={Clickable} variant="secondary" onClick={() => setQuantity(Math.max(1, quantity - 1))}>-</Button>
              <Text>{quantity}</Text>
              <Button as={Clickable} variant="secondary" onClick={() => setQuantity(Math.min(maxStock, quantity + 1))}>+</Button>
            </Row>
            <Button
              as={Clickable}
              variant="primary"
              disabled={isOutOfStock}
              onClick={handleAddToCart}
            >
              Add to Cart
            </Button>
          </Row>
        </Card>
      </Stack>
    </Container>


  );
}

