interface Props {
  title: string; // Chat window title
  currentUser: string; // Current user name (for right-aligning own messages)
  participantCount: number; // Number of participants
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>; // Initial messages to display on mount
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when user sends a message. Payload: { text, timestamp } */
type ActionSendMessagePayload = { text: string; timestamp: string };


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: New message from another participant — append to message list */
type StreamMessage = { sender?: string; text?: string; timestamp?: string };

/** Stream event: Typing indicator — show/hide based on active flag */
type StreamTyping = { sender?: string; active?: boolean };




const TypingIndicator = ({ name }: { name: string }) => (
  <Box padding="var(--ggui-spacing-2)">
    <Row gap="var(--ggui-spacing-2)" align="center">
      <Spinner size={16} />
      <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
        {name} is typing...
      </Text>
    </Row>
  </Box>
);



const MessageBubble = ({ sender, text, timestamp, isOwn, isGrouped }: { sender: string; text: string; timestamp: string; isOwn: boolean; isGrouped?: boolean }) => (
  <Stack align={isOwn ? 'end' : 'start'} gap="var(--ggui-spacing-1)">
    {!isGrouped && (
      <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
        {sender} • {new Date(timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
      </Text>
    )}
    <Box
      paddingX="var(--ggui-spacing-4)"
      paddingY="var(--ggui-spacing-2)"
      borderRadius="var(--ggui-shape-radius-lg)"
      background={isOwn ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-surfaceVariant)'}
    >
      <Text color={isOwn ? 'var(--ggui-color-onContainer)' : 'var(--ggui-color-onSurfaceVariant)'}>
        {text}
      </Text>
    </Box>
  </Stack>
);



export default function Component(props: Props) {

  // DO NOT EDIT wire hooks — auto-generated from the data contract
  const sendMessage = useAction<ActionSendMessagePayload>('sendMessage'); // Called when user sends a message. Payload: { text, timestamp }
  const message = useStream<StreamMessage>('message'); // New message from another participant — append to message list
  const typing = useStream<StreamTyping>('typing'); // Typing indicator — show/hide based on active flag

  const [messages, setMessages] = useState(props.messages || []);
  const [inputValue, setInputValue] = useState('');
  const scrollRef = useRef<HTMLDivElement>(null);

  // Sync incoming stream messages
  useEffect(() => {
    if (message.latest) {
      setMessages((prev) => [...prev, message.latest!]);
    }
  }, [message.latest]);

  // Auto-scroll to bottom
  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, typing.latest]);

  const handleSend = useCallback(() => {
    if (inputValue.trim()) {
      const newMsg = {
        sender: props.currentUser,
        text: inputValue,
        timestamp: new Date().toISOString(),
      };
      sendMessage({ text: newMsg.text, timestamp: newMsg.timestamp });
      setMessages((prev) => [...prev, newMsg]);
      setInputValue('');
    }
  }, [inputValue, props.currentUser, sendMessage]);

  const typingUser = useMemo(() => (typing.latest?.active ? typing.latest.sender : null), [typing.latest]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-4)" style={{ height: '80vh' }}>
        {/* Header */}
        <Card padding="var(--ggui-spacing-4)">
          <Row justify="between" align="center">
            <Heading level={3}>{props.title}</Heading>
            <Badge variant="default">{props.participantCount} participants</Badge>
          </Row>
        </Card>

        {/* Message List */}
        {/* Message List */}
        <Box
          ref={scrollRef}
          role="log"
          aria-live="polite"
          aria-atomic="true"
          background="var(--ggui-color-surface)"
          padding="var(--ggui-spacing-4)"
          borderRadius="var(--ggui-shape-radius-lg)"
          style={{ flex: 1, overflowY: 'auto', border: '1px solid var(--ggui-color-outlineVariant)' }}
        >
          <Stack gap="var(--ggui-spacing-4)">
            {messages.map((msg, i) => {
              const prev = messages[i - 1];
              const isGrouped = prev && prev.sender === msg.sender;
              return (
                <React.Fragment key={i}>
                  <MessageBubble
                    sender={isGrouped ? '' : (msg.sender || 'Unknown')}
                    text={msg.text || ''}
                    timestamp={msg.timestamp || new Date().toISOString()}
                    isOwn={msg.sender === props.currentUser}
                    isGrouped={isGrouped}
                  />
                </React.Fragment>
              );
            })}
            {typingUser && <TypingIndicator name={typingUser} />}
          </Stack>
        </Box>


        {/* Input Area */}
        <Row gap="var(--ggui-spacing-2)">
          <Box style={{ flex: 1 }}>
            <Input
              label="Message"
              placeholder="Type a message..."
              value={inputValue}
              onChange={setInputValue}
              onKeyDown={(e: React.KeyboardEvent) => e.key === 'Enter' && handleSend()}
            />
          </Box>
          <Button
            variant="primary"
            disabled={!inputValue.trim()}
            as={Clickable}
            onClick={handleSend}
          >
            Send
          </Button>
        </Row>
      </Stack>
    </Container>
  );
}

