export default function Component(props: Props) {
  const priceUpdate = useStream<StreamPriceUpdate>('priceUpdate');
  const marketStatus = useStream<StreamMarketStatus>('marketStatus');

  const [stocks, setStocks] = useState(props.stocks);
  const [lastUpdated, setLastUpdated] = useState(new Date());

  useEffect(() => {
    if (priceUpdate.latest) {
      setStocks(prev => prev.map(s => s.symbol === priceUpdate.latest?.symbol ? { ...s, ...priceUpdate.latest } : s));
      setLastUpdated(new Date());
    }
  }, [priceUpdate.latest]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <MotionKeyframes />
