        <CardGrid columns={{ sm: 1, md: 2, lg: 3 }} gap={16}>
          {stocks.map((s, i) => <StockCard key={s.symbol || i} stock={s} />)}
        </CardGrid>
      </Stack>
    </Container>
  );
}

