import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  initialProfile: { name?: string; email?: string; avatar?: string; role?: string; emailNotifications?: boolean; theme?: string }; // Pre-filled profile data for editing (all fields optional)
  avatarOptions: string[]; // Available avatar emojis to choose from
  roleOptions: string[]; // Available role options for the dropdown
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all profile data when user completes onboarding */
type ActionCompletePayload = { name: string; email: string; avatar: string; role: string; emailNotifications: boolean; theme: string };





export default function Component(props: Props) {
  const [step, setStep] = useState(1);
  const [name, setName] = useState(props.initialProfile?.name || '');
  const [email, setEmail] = useState(props.initialProfile?.email || '');
  const [avatar, setAvatar] = useState(props.initialProfile?.avatar || props.avatarOptions[0] || '');
  const [role, setRole] = useState(props.initialProfile?.role || props.roleOptions[0] || '');

  const [emailNotifications, setEmailNotifications] = useState(props.initialProfile?.emailNotifications ?? true);
  const [theme, setTheme] = useState(props.initialProfile?.theme || 'light');


  const emailValid = useMemo(() => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email), [email]);
  const step1Valid = name.trim().length > 0 && emailValid;

  const complete = useAction<ActionCompletePayload>('complete');

  const handleSubmit = () => {
    complete({ name, email, avatar, role, emailNotifications, theme });
  };

  const progress = (step / 3) * 100;

  return (
    <Container maxWidth="md" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Stack gap="var(--ggui-spacing-2)">
          <Row justify="between">
            <Heading level={3}>Onboarding {step}/3</Heading>
            <Text variant="label">{Math.round(progress)}%</Text>
          </Row>
          <Progress value={step} max={3} variant="default" size="md" />
        </Stack>

        <Card padding="var(--ggui-spacing-6)">
          {step === 1 && (
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={4}>Profile Setup</Heading>
              <Input label="Name" value={name} onChange={setName} required />
              <Input label="Email" type="email" value={email} onChange={setEmail} error={email && !emailValid ? 'Invalid email format' : undefined} required />
              <Stack gap="var(--ggui-spacing-2)">
                <Text variant="label">Avatar Selection</Text>
                <Row gap="var(--ggui-spacing-2)">
                  {props.avatarOptions.map((a) => (
                    <Box 
                      key={a} 
                      as={Clickable} 
                      onClick={() => setAvatar(a)} 
                      role="radio" 
                      aria-label={`Select avatar ${a}`}
                      padding="var(--ggui-spacing-3)" 
                      background={avatar === a ? 'var(--ggui-color-primary-100)' : 'var(--ggui-color-surfaceVariant)'} 
                      borderRadius="var(--ggui-shape-radius-md)"
                      style={{ cursor: 'pointer', transition: 'background 0.2s' }}
                      onMouseEnter={(e: any) => e.currentTarget.style.background = 'var(--ggui-color-primary-50)'}
                      onMouseLeave={(e: any) => e.currentTarget.style.background = avatar === a ? 'var(--ggui-color-primary-100)' : 'var(--ggui-color-surfaceVariant)'}
                    >
                      <Text size="2xl">{a}</Text>
                    </Box>
                  ))}
                </Row>
              </Stack>
            </Stack>
          )}


          {step === 2 && (
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={4}>Preferences</Heading>
              <Select label="Role" value={role} onChange={setRole} options={props.roleOptions.map(r => ({ value: r, label: r }))} />

              <Row justify="between" align="center">
                <Toggle label="Email Notifications" checked={emailNotifications} onChange={setEmailNotifications} />
              </Row>
              <Row justify="between" align="center">
                <Toggle label="Dark Mode" checked={theme === 'dark'} onChange={(c) => setTheme(c ? 'dark' : 'light')} />
              </Row>

            </Stack>
          )}

          {step === 3 && (
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={4}>Review & Confirm</Heading>
              <Stack gap="var(--ggui-spacing-2)">
                <Text><strong>Name:</strong> {name}</Text>
                <Text><strong>Email:</strong> {email}</Text>
                <Text><strong>Role:</strong> {role}</Text>
                <Text><strong>Avatar:</strong> {avatar}</Text>
                <Text><strong>Notifications:</strong> {emailNotifications ? 'Enabled' : 'Disabled'}</Text>
                <Text><strong>Theme:</strong> {theme}</Text>
              </Stack>
            </Stack>
          )}

          <Spacer size={24} />
          <Row gap="var(--ggui-spacing-2)" justify="end">
            {step > 1 && <Button variant="secondary" onClick={() => setStep(s => s - 1)}>Go Back</Button>}
            {step < 3 ? (
              <Button disabled={step === 1 && !step1Valid} onClick={() => setStep(s => s + 1)}>Next</Button>
            ) : (
              <Button variant="primary" onClick={handleSubmit}>Complete Setup</Button>
            )}
          </Row>
        </Card>
      </Stack>
    </Container>
  );
}
